const raw = $input.first().json.message?.content ?? $input.first().json.choices?.[0]?.message?.content;
const parsed = JSON.parse(raw);
const input = $('Podcast Job Trigger').first().json;

return [{
  topic: input.topic,
  narration: parsed.narration,
  intro_sentence: parsed.intro_sentence,
  segments: parsed.segments,
  voice_clone_id: input.voice_clone_id,
  avatar_id: input.avatar_id,
  voice_id: input.voice_id,
  notify_chat_id: input.notify_chat_id,
  job_id: `podcast_${Date.now()}`,
  started_at: new Date().toISOString()
}];

// Merge artifacts from all three generation branches
const voice = $('ElevenLabs Voice Track').first().json;
const heygen = $('HeyGen Avatar Intro').first().json;
const kling = $('Kling B-Roll (Parallel)').first().json;

return [{
  job_id: $('Parse & Enrich Script').first().json.job_id,
  status: 'generation_submitted',
  elevenlabs_binary_ready: !!voice,
  heygen_video_id: heygen?.data?.video_id ?? null,
  kling_task_id: kling?.task_id ?? null,
  summary: 'All generation jobs submitted. ElevenLabs audio ready. HeyGen and Kling are async — monitor via callbacks.',
  completed_at: new Date().toISOString()
}];
